SQLLite.SQL:
UPDATE PAYMENTS PAY
SET    PAY.PAYABLE_ORDER_NUMBER_2 = ${param.poNumber}
,      PAY.PAYOUT_DATE            = TO_DATE(${param.itemDate}, 'YYYY-MM-DD')
,      PAY.PAYOUT_REPORT_ID       = ${param.reportId}
WHERE  PAY.ADMIN_COURT_CODE       = ${param.adminCourtCode}
AND    PAY.TRANSACTION_NUMBER     = ${param.transactionNumber}
